      up_rdata <= up_rdata_cntrl_s;
    end
  end

  axi_ad7616_pif i_ad7616_parallel_interface (
    .cs_n (rx_cs_n),
    .db_o (rx_db_o),
    .db_i (rx_db_i),
    .db_t (rx_db_t),
